import json
import pytest
from solution import to_pretty_json, from_pretty_json

def test_preserves_native_unicode():
    s = to_pretty_json({'name': 'אלון'})
    assert 'אלון' in s
    assert '\\u05d0' not in s

def test_indent_is_two():
    s = to_pretty_json({'a': 1, 'b': 2})
    assert '\n  "a"' in s

def test_keys_are_sorted():
    s = to_pretty_json({'b': 2, 'a': 1})
    assert s.index('"a"') < s.index('"b"')

def test_round_trip_preserves_data():
    obj = {'name': 'аня', 'count': 7, 'tags': ['x', 'y']}
    assert from_pretty_json(to_pretty_json(obj)) == obj

