import csv
import io

def sum_column(csv_text, column):
    reader = csv.DictReader(io.StringIO(csv_text))
    if column not in (reader.fieldnames or []):
        raise KeyError(column)
    return sum(int(row[column]) for row in reader)

cards.tests:
import pytest
from solution import sum_column

CSV = 'name,amount\nalice,100\nbob,200\ncarol,50\n'

def test_sums_the_amount_column():
    assert sum_column(CSV, 'amount') == 350

def test_unknown_column_raises_keyerror():
    with pytest.raises(KeyError):
        sum_column(CSV, 'nope')

def test_empty_data_returns_zero():
    assert sum_column('amount\n', 'amount') == 0

def test_single_row():
    assert sum_column('amount\n42\n', 'amount') == 42
